    /** Attempts to seat a patron with the given name in the first empty seat found,
     *  scanning row 0 left-to-right, then row 1 left-to-right, and so on.
     *  Returns true if seated, or false if the section is full.
     *  Implementation in part (b). */
    public boolean seatPatron(String name) { /* implementation in part (b) */ }
