frq_section.reference_solution:
public class Theater {
    private String[][] seats;

    public Theater(int numRows, int numCols) {
        seats = new String[numRows][numCols];
        for (int r = 0; r < numRows; r++) {
            for (int c = 0; c < numCols; c++) {
                seats[r][c] = "";
            }
        }
    }

    public boolean isEmpty(int r, int c) {
        return seats[r][c].equals("");
    }

    public boolean seatPatron(String name) {
        for (int r = 0; r < seats.length; r++) {
            for (int c = 0; c < seats[r].length; c++) {
                if (seats[r][c].equals("")) {
                    seats[r][c] = name;
                    return true;
                }
            }
        }
        return false;
    }

    public String getSeat(int r, int c) {
        return seats[r][c];
    }
}

